#include <stdio.h>
#include <math.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        double D, U;
        int N;
        scanf("%lf %lf %d", &D, &U, &N);
        double defaultCost = D * U;
        int bestIdx = 0;
        double bestCost = defaultCost;
        for (int i = 1; i <= N; ++i) {
            int M;
            double R, C;
            scanf("%d %lf %lf", &M, &R, &C);
            double avg = R * U + C / M;
            if (avg < bestCost - 1e-9) {
                bestCost = avg;
                bestIdx = i;
            }
        }
        printf("%d\n", bestIdx);
    }
    return 0;
}

